// Extract message and user info
const message = items[0].json.message || {};

const userId = message.from?.id?.toString() || 'unknown';
const username = message.from?.username || message.from?.first_name || 'User';
const chatId = message.chat?.id;
const text = message.text || '';

return [{
  json: {
    userId,
    username,
    chatId,
    text,
    timestamp: new Date().toISOString()
  }
}];

// User profile configuration
// In production, fetch from database using userId
return [{
  json: {
    userId: $json.userId,
    name: 'Your Name',
    currentRole: 'Senior Backend Engineer',
    targetRole: 'Staff Engineer',
    experience: '5 years',
    skills: ['Python', 'Node.js', 'AWS', 'Docker', 'Kubernetes', 'PostgreSQL'],
    location: 'Hyderabad, India',
    workMode: 'Remote or Hybrid',
    minSalary: 80000,
    sheetId: 'YOUR_SPREADSHEET_ID',
    resumeUrl: 'https://drive.google.com/file/d/YOUR_RESUME_ID/view'
  }
}];

// Build dynamic system prompt
const config = items[0].json;
const userMessage = $('Extract Message').item.json;

const systemPrompt = `You are ${config.name}'s personal job hunt assistant.

**User Profile:**
- Current Role: ${config.currentRole}
- Target Role: ${config.targetRole}
- Experience: ${config.experience}
- Skills: ${config.skills.join(', ')}
- Location: ${config.location}
- Work Preference: ${config.workMode}
- Minimum Salary: $${config.minSalary}

**Your Capabilities:**
1. Query job tracker (see applications, stats, pending jobs)
2. Send emails to recruiters (draft and send on user command)
3. Provide resume information
4. Answer job search questions

**Guidelines:**
- Be concise and action-oriented
- Suggest next steps
- Confirm before sending emails
- Use bullet points for lists
- Keep responses under 300 words

User message: ${userMessage.text}`;

return [{
  json: {
    ...items[0].json,
    systemPrompt,
    userMessage: userMessage.text
  }
}];

// Parse agent response and extract actions
const response = items[0].json.response || items[0].json.text || 'Sorry, I could not process your request.';
const userMessage = $('Extract Message').item.json.text.toLowerCase();

// Detect action intents
const needsSheetQuery = userMessage.includes('stats') || userMessage.includes('status') || userMessage.includes('how many');
const needsEmail = userMessage.includes('send email') || userMessage.includes('apply');
const needsResume = userMessage.includes('resume') || userMessage.includes('cv');

return [{
  json: {
    ...items[0].json,
    response,
    needsSheetQuery,
    needsEmail,
    needsResume
  }
}];

// Aggregate sheet stats
const jobs = items.map(item => item.json);

const total = jobs.length;
const statusCounts = jobs.reduce((acc, j) => {
  const status = j.Status || 'Unknown';
  acc[status] = (acc[status] || 0) + 1;
  return acc;
}, {});

const stats = `**Your Job Tracker Stats:**\n` +
  `• Total jobs: ${total}\n` +
  Object.entries(statusCounts).map(([status, count]) => 
    `• ${status}: ${count}`
  ).join('\n');

return [{
  json: {
    ...items[0].json,
    stats
  }
}];

// Quick command handler
const text = $('Extract Message').item.json.text.toLowerCase();
const config = $('Fetch User Config').item.json;

let quickResponse = '';

if (text === '/start' || text === '/help') {
  quickResponse = `**Job Hunt Assistant**\n\nCommands:\n• /stats - View your application stats\n• /search [keywords] - Find new jobs\n• /resume - View your resume\n• Ask me anything about your job search!`;
} else if (text === '/resume') {
  quickResponse = `**Your Resume:**\n${config.resumeUrl}\n\n**Profile:**\n• ${config.currentRole}\n• ${config.experience}\n• Skills: ${config.skills.join(', ')}`;
}

return [{
  json: {
    ...items[0].json,
    quickResponse
  }
}];
